const fs = require('fs'), http = require('http');
const raw = $input.first().json;
const body = raw.body || raw;

// ============================================================
// LOOP GUARD — prevents agent callbacks from re-triggering fan out
// Agent callbacks arrive at /webhook/aidan-orchestra with an 'agent' field.
// If this is a callback from an agent, route to callback handler, not fan out.
// ============================================================
if (body.agent && ['Scout','Jordan','Iris','Atlas','Nova','Sage','Pulse'].includes(body.agent)) {
  return [{ json: { ...body, _isCallback: true, _guardTriggered: true } }];
}

const masterQuery = String(body.query || body.command || 'Full platform status — compliance, BD targets, grant pipeline, technology milestones.');
const sessionId = 'orch_' + Date.now();
fs.mkdirSync('/data/Aidan_Outputs/Orchestra', { recursive: true });
fs.writeFileSync(`/data/Aidan_Outputs/Orchestra/session_${sessionId}.json`, JSON.stringify({ sessionId, masterQuery, startTime: new Date().toISOString(), agents: { Atlas: null, Scout: null, Jordan: null, Iris: null } }, null, 2), 'utf8');

// ============================================================
// FAN OUT — fires all four agents in parallel
// Atlas status: current platform status
// Scout: top 3 DMV contract/grant opportunities
// Jordan: grant pipeline status
// Iris: compliance and deadline watchlist
// ============================================================
const agentCalls = [
  { path: '/webhook/atlas-architect', payload: { command: 'Atlas status', detail: masterQuery, sessionId } },
  { path: '/webhook/scout-research', payload: { query: masterQuery + ' — top 3 DMV contract opportunities', sessionId } },
  { path: '/webhook/grant-writer', payload: { trigger: 'orchestra', query: masterQuery, sessionId } },
  { path: '/webhook/iris-monitor', payload: { trigger: 'orchestra', sessionId } }
];

const fireAgent = (agentPath, payload) => new Promise(resolve => {
  const bodyStr = JSON.stringify(payload);
  const opts = { hostname: 'host.docker.internal', port: 5678, path: agentPath, method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(bodyStr) } };
  const req = http.request(opts, res => { res.on('data',()=>{}); res.on('end', () => resolve({ path: agentPath, fired: true })); });
  req.on('error', e => resolve({ path: agentPath, fired: false, error: e.message }));
  req.write(bodyStr); req.end();
});

const results = await Promise.all(agentCalls.map(a => fireAgent(a.path, a.payload)));
const agentNames = ['Atlas','Scout','Jordan','Iris'];
const launchMsg = `🎼 ORCHESTRA LAUNCHED\n\n${agentNames.map((a,i) => `${results[i].fired?'✅':'❌'} ${a}`).join('\n')}\n\nConsolidated brief incoming ~2 minutes.`;

const msgBody = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: launchMsg } });
const waOpts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(msgBody) } };
await new Promise(r => { const req = http.request(waOpts, res => { res.on('data',()=>{}); res.on('end',r); }); req.on('error',r); req.write(msgBody); req.end(); });

return [{ json: { sessionId, masterQuery, results, launched: true, _isCallback: false } }];

const fs = require('fs'), http = require('http'), https = require('https');
const raw = $input.first().json;
const body = raw.body || raw;

// ============================================================
// CALLBACK CONSOLIDATOR
// Waits for all four agents within a 15-minute window before synthesizing.
// Window widened from 5 to 15 minutes to account for Claude API latency.
// ============================================================
const agentName = body.agent || 'Unknown';
const timestamp = body.timestamp || new Date().toISOString();
fs.mkdirSync('/data/Aidan_Outputs/Callbacks', { recursive: true });
fs.writeFileSync(`/data/Aidan_Outputs/Callbacks/${agentName}_${timestamp.replace(/[:.]/g,'-')}.json`, JSON.stringify(body, null, 2), 'utf8');

const cbDir = '/data/Aidan_Outputs/Callbacks/';
const allFiles = fs.readdirSync(cbDir).filter(f => f.endsWith('.json'));
const cutoff = Date.now() - (15 * 60 * 1000);
const recentCallbacks = {};
allFiles.forEach(f => {
  try {
    const stat = fs.statSync(cbDir + f);
    if (stat.mtimeMs > cutoff) {
      const data = JSON.parse(fs.readFileSync(cbDir + f, 'utf8'));
      if (data.agent) recentCallbacks[data.agent] = data;
    }
  } catch(e) {}
});

const allFour = ['Atlas','Scout','Jordan','Iris'].every(a => Object.keys(recentCallbacks).includes(a));
if (!allFour) return [{ json: { received: agentName, waiting: true, receivedSoFar: Object.keys(recentCallbacks), allFour: false } }];

const atlas = recentCallbacks['Atlas'] || {};
const scout = recentCallbacks['Scout'] || {};
const jordan = recentCallbacks['Jordan'] || {};
const iris = recentCallbacks['Iris'] || {};

const systemMessage = `You are Aidan, Chief of Staff to Kevin Alexander Smith, CEO of KAI-Netics. Synthesize four agent reports into a single executive morning briefing. BLUF first. Entity-tagged action items. Decisive and concise — Kevin reads this on his phone. Priority order: EAF compliance > FP contracts > MONK IP. Clearly separate what Kevin must decide today from what Aidan handles autonomously.`;

const userMessage = `Synthesize these four agent reports into the morning brief:\n\nATLAS (Platform Status):\n${atlas.summary || atlas.statusReport || 'No report'}\n\nSCOUT (BD & Grant Intel):\n${scout.summary || 'No report'}\nFit Score: ${scout.fitScore || 'N/A'} | Source: ${scout.sourceLabel || 'N/A'}\n\nJORDAN (Grant Pipeline):\n${jordan.summary || 'No report'}\nFit Score: ${jordan.fitScore || 'N/A'}\n\nIRIS (Compliance & Deadlines):\n${iris.summary || 'No report'}\nCritical: ${iris.criticalCount || 0} | Urgent: ${iris.urgentCount || 0}\n\nFormat the brief exactly as follows:\n\n🎯 BLUF\n[3 sentences max — what matters most today]\n\n🔴 KEVIN DECIDES TODAY\n[Numbered list — items requiring Kevin's direct action or decision]\n\n📋 AIDAN HANDLES\n[Numbered list — items Aidan executes autonomously, no Kevin decision needed]\n\n📊 INTEL SUMMARY\nAtlas: [1-2 sentences]\nScout: [1-2 sentences — top opportunity and fit score]\nJordan: [1-2 sentences — top grant and fit score]\nIris: [1-2 sentences — most urgent compliance item]\n\n⚠️ FLAGS & RISKS\n[Bulleted list — anything needing attention in next 7 days]`;

const requestBody = JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 2048, system: systemMessage, messages: [{ role: 'user', content: userMessage }] });
const apiOptions = { hostname: 'api.anthropic.com', port: 443, path: '/v1/messages', method: 'POST', headers: { 'Content-Type': 'application/json', 'x-api-key': 'REPLACE_WITH_KEY', 'anthropic-version': '2023-06-01', 'Content-Length': Buffer.byteLength(requestBody) } };

const result = await new Promise((resolve, reject) => {
  const req = https.request(apiOptions, (res) => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode, body: d })); });
  req.on('error', reject); req.write(requestBody); req.end();
});

let brief = '';
try { brief = JSON.parse(result.body).content?.[0]?.text || 'Consolidation failed.'; } catch(e) { brief = 'Parse error: ' + result.body.substring(0,500); }

const briefPath = `/data/Aidan_Outputs/Orchestra/Brief_${new Date().toISOString().replace(/[:.]/g,'-')}.txt`;
fs.writeFileSync(briefPath, brief, 'utf8');

const fullMsg = `🎼 AIDAN MORNING BRIEF\n${new Date().toLocaleString('en-US',{timeZone:'America/New_York'})} EST\n\n${brief}`;
const chunks = [];
for (let i = 0; i < fullMsg.length; i += 3800) chunks.push(fullMsg.substring(i, i + 3800));
for (const chunk of chunks) {
  const mb = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: chunk } });
  const wo = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(mb) } };
  await new Promise(r => { const req = http.request(wo, res => { res.on('data',()=>{}); res.on('end',r); }); req.on('error',r); req.write(mb); req.end(); });
  await new Promise(r => setTimeout(r, 1000));
}

return [{ json: { success: true, allFour: true, briefPath } }];
